INSERT INTO biosecurity_guides (id, title, content) VALUES
(1, 'Biosecurity Measures for Livestock Farms', '1. Limit access to your farm. Only allow essential personnel. 2. Clean and disinfect equipment before entering your farm. 3. Implement a strict visitor log. 4. Use separate clothing and footwear for farm work. 5. Regularly monitor animal health and report any unusual symptoms.'),
(2, 'Quarantine Procedures', '1. Isolate new animals for at least 30 days before introducing them to the herd. 2. Monitor quarantined animals closely for signs of illness. 3. Keep quarantine areas separate from the main farm. 4. Disinfect all equipment used in quarantine areas.'),
(3, 'Sanitation Protocols', '1. Regularly clean and disinfect all animal housing and feeding areas. 2. Use appropriate disinfectants that are effective against FMD. 3. Ensure proper waste disposal methods are in place. 4. Maintain a clean water supply for livestock.'),
(4, 'Emergency Response Plan', '1. Have a clear plan in place for reporting suspected disease outbreaks. 2. Train all farm staff on biosecurity measures and emergency protocols. 3. Establish communication channels with local veterinarians and authorities. 4. Keep emergency contact numbers readily available.');